const body = $json.body ?? $json;
const lat = Number(body.lat);
const lng = Number(body.lng);
const radius = Number(body.radius ?? 1500);
const query = String(body.query ?? '').trim();

if (!Number.isFinite(lat) || !Number.isFinite(lng) || !query) {
  throw new Error('Invalid input: lat/lng/query are required');
}

return [{
  json: {
    userContext: { lat, lng, original_query: query, radius },
    placesRequest: {
      textQuery: query + ' restaurant',
      locationBias: {
        circle: {
          center: { latitude: lat, longitude: lng },
          radius
        }
      }
    }
  }
}];

const upstream = $item(0).$node['Build Request'].json;
const userContext = upstream.userContext ?? {};
const query = String(userContext.original_query ?? '').toLowerCase();

const fallback = [
  { name: 'Mock 兰州拉面', address: 'Mock Road 1', rating: 4.2, priceLevel: 'PRICE_LEVEL_INEXPENSIVE', location: { latitude: userContext.lat ?? null, longitude: userContext.lng ?? null }, googleMapsUri: null },
  { name: 'Mock 牛肉面馆', address: 'Mock Road 2', rating: 4.0, priceLevel: 'PRICE_LEVEL_MODERATE', location: { latitude: userContext.lat ?? null, longitude: userContext.lng ?? null }, googleMapsUri: null }
];

const places = Array.isArray($json.places) ? $json.places : [];
const usingFallback = places.length === 0;

const normalized = (usingFallback ? fallback : places).map((p, idx) => {
  const name = p.displayName?.text ?? p.name ?? `unknown_${idx}`;
  const address = p.formattedAddress ?? p.address ?? '';
  const rating = Number(p.rating ?? 0);
  const priceLevel = p.priceLevel ?? 'PRICE_LEVEL_UNSPECIFIED';
  const location = p.location ?? p.location ?? {};
  const googleMapsUri = p.googleMapsUri ?? null;

  const isCheapIntent = query.includes('便宜') || query.includes('cheap');
  const isNoodleIntent = query.includes('拉面') || query.includes('noodle');

  const pricePenaltyMap = {
    PRICE_LEVEL_VERY_EXPENSIVE: 30,
    PRICE_LEVEL_EXPENSIVE: 20,
    PRICE_LEVEL_MODERATE: 8,
    PRICE_LEVEL_INEXPENSIVE: 0,
    PRICE_LEVEL_UNSPECIFIED: 5
  };

  let score = rating * 20 - (pricePenaltyMap[priceLevel] ?? 10);
  if (isCheapIntent && priceLevel === 'PRICE_LEVEL_INEXPENSIVE') score += 10;
  if (isNoodleIntent && /面|拉面|noodle/i.test(name)) score += 8;

  return { name, address, rating, priceLevel, location, googleMapsUri, score: Number(score.toFixed(2)) };
});

normalized.sort((a, b) => b.score - a.score);

return [{
  json: {
    input_echo: userContext,
    fallback_used: usingFallback,
    nearby_restaurants: normalized.slice(0, 10),
    recommendation: normalized[0] ?? null
  }
}];

