const places = Array.isArray($json.places) ? $json.places : [];
const cleaned = places.map((p, idx) => ({
  name: p.displayName?.text ?? p.name ?? `unknown_${idx}`,
  address: p.formattedAddress ?? '',
  rating: Number(p.rating ?? 0),
  priceLevel: p.priceLevel ?? 'PRICE_LEVEL_UNSPECIFIED',
  location: p.location ?? {},
  googleMapsUri: p.googleMapsUri ?? null
}));

return [{ json: { cleaned } }];

output.scoring_code:
const query = String($json.input_echo?.original_query ?? '').toLowerCase();
const pricePenaltyMap = {
  PRICE_LEVEL_VERY_EXPENSIVE: 30,
  PRICE_LEVEL_EXPENSIVE: 20,
  PRICE_LEVEL_MODERATE: 8,
  PRICE_LEVEL_INEXPENSIVE: 0,
  PRICE_LEVEL_UNSPECIFIED: 5
};

const scored = ($json.cleaned ?? []).map((r) => {
  const isCheapIntent = query.includes('便宜') || query.includes('cheap');
  const isNoodleIntent = query.includes('拉面') || query.includes('noodle');

  let score = Number(r.rating ?? 0) * 20 - (pricePenaltyMap[r.priceLevel] ?? 10);
  if (isCheapIntent && r.priceLevel === 'PRICE_LEVEL_INEXPENSIVE') score += 10;
  if (isNoodleIntent && /面|拉面|noodle/i.test(r.name)) score += 8;

  return { ...r, score: Number(score.toFixed(2)) };
}).sort((a, b) => b.score - a.score);

return [{ json: { nearby_restaurants: scored, recommendation: scored[0] ?? null } }];
